(window.webpackJsonp=window.webpackJsonp||[]).push([[716],{689:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">ranges</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minTaps = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, ranges</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> inter=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;ranges.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> s=i-ranges[i]\\n    <span class=\\"hljs-keyword\\">let</span> e=ranges[i]+i\\n    <span class=\\"hljs-keyword\\">if</span>(e===<span class=\\"hljs-number\\">0</span>)inter.push([<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>])\\n    inter.push([<span class=\\"hljs-built_in\\">Math</span>.max(<span class=\\"hljs-number\\">0</span>,s),<span class=\\"hljs-built_in\\">Math</span>.min(n,e)])\\n  }\\n  inter.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]===b[<span class=\\"hljs-number\\">0</span>] ? b[<span class=\\"hljs-number\\">1</span>]-a[<span class=\\"hljs-number\\">1</span>] : a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>])\\n  <span class=\\"hljs-keyword\\">let</span> slimInter=uniq(inter)\\n  \\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">let</span> allS=slimInter[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">let</span> allE=slimInter[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">1</span>]\\n  <span class=\\"hljs-keyword\\">if</span>(allS&gt;<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">if</span>(allS===<span class=\\"hljs-number\\">0</span> &amp;&amp; allE===n)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">1</span>\\n  \\n  <span class=\\"hljs-keyword\\">while</span>(allE!==n){\\n    <span class=\\"hljs-keyword\\">let</span> newAllE=filt(slimInter,allE)\\n    res++\\n    <span class=\\"hljs-keyword\\">if</span>(allE===newAllE)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n    allE=newAllE\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">filt</span>(<span class=\\"hljs-params\\">arr,limit</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> maxEnd=<span class=\\"hljs-number\\">-1</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(arr[i][<span class=\\"hljs-number\\">0</span>]&lt;=limit){\\n        maxEnd=<span class=\\"hljs-built_in\\">Math</span>.max(maxEnd,arr[i][<span class=\\"hljs-number\\">1</span>])\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> maxEnd\\n  }\\n  \\n\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">uniq</span>(<span class=\\"hljs-params\\">inter</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> slimInter=[]\\n    <span class=\\"hljs-keyword\\">let</span> lastS=inter[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]\\n    <span class=\\"hljs-keyword\\">let</span> lastE=inter[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">1</span>]\\n    slimInter.push([lastS,lastE])\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;inter.length;i++){\\n      <span class=\\"hljs-keyword\\">let</span> [curS,curE]=inter[i]\\n      <span class=\\"hljs-keyword\\">if</span>(include([lastS,lastE],inter[i]))<span class=\\"hljs-keyword\\">continue</span>\\n      slimInter.push([curS,curE])\\n      lastS=curS\\n      lastE=curE\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> slimInter\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">include</span>(<span class=\\"hljs-params\\">[ls,le],[cs,ce]</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(ls&lt;=cs &amp;&amp; le&gt;=ce)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-number-of-taps-to-open-to-water-a-garden","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<ol>\\n<li>\\n<p>\u7b97\u51fa\u6bcf\u4e00\u4e2a\u6c34\u9f99\u5934\u7684\u8303\u56f4\uff0c\u7ec4\u6210\u4e00\u4e2a\u6570\u7ec4<code>arr</code></p>\\n</li>\\n<li>\\n<p>\u5bf9\u8fd9\u4e2a\u6570\u7ec4\u8fdb\u884c\u6392\u5e8f\uff0c\u5e76\u4e14\u53bb\u91cd\uff0c\u4fdd\u8bc1\u6bcf\u4e00\u4e2a\u8303\u56f4\u90fd\u4e0d\u4f1a\u5305\u542b\u4efb\u610f\u53e6\u4e00\u4e2a\u8303\u56f4</p>\\n</li>\\n<li>\\n<p>\u4ece\u7b2c\u4e00\u4e2a\u8303\u56f4<code>arr[0]</code>\u5f00\u59cb(\u56e0\u4e3a\u53ea\u53ef\u80fd\u6709\u7b2c\u4e00\u4e2a\u8303\u56f4\u5305\u62ec<code>0</code>)\uff0c\u7b5b\u9009\u51fa\u540e\u7eed\u7684\u6bcf\u4e00\u4e2a\u8303\u56f4<code>inter</code>\u4e2d\uff0c\u7b26\u5408<code>inter[0]&lt;=arr[0][1]</code>\u6761\u4ef6\u7684<code>inter[1]</code>\u7684\u6700\u5927\u503c\u3002</p>\\n<p>\u4f8b\u5982\uff1a\u4e00\u7ec4<code>arr=[[0,4],[1,5],[2,6],[3,7]]</code></p>\\n<p>\u90a3\u4e48\u7b2c\u4e00\u4e2a\u8303\u56f4\u662f<code>[0,4]</code>\uff0c\u800c\u540e\u7eed\u7b5b\u9009\u51fa\u6700\u5927\u7684\u7ed3\u679c\u5219\u662f<code>[3,7]</code>\uff0c\u56e0\u4e3a<code>3</code>\u80fd\u6ee1\u8db3<code>3&lt;=4</code>\uff0c\u5e76\u4e14<code>7</code>\u662f\u80fd\u6ee1\u8db3\u8fd9\u4e9b\u6761\u4ef6\u4e2d\u7684\u6700\u5927\u503c\u3002</p>\\n</li>\\n<li>\\n<p>\u5c06\u7b2c\u4e00\u4e2a\u8303\u56f4\u66f4\u65b0\u4e3a\u4e0a\u4e00\u6b21\u7684\u5e76\u96c6\uff0c\u91cd\u590d\u7b2c3\u6b65(\u66f4\u4f18\u5316\u7684\u505a\u6cd5\u662f\u8bb0\u5f55\u4e4b\u524d\u68c0\u67e5\u8fc7\u7684\u8303\u56f4\uff0c\u4e0d\u518d\u6b21\u68c0\u67e5<code>O(N)</code>)\uff0c\u76f4\u5230\u8303\u56f4\u4e0d\u80fd\u518d\u6b21\u66f4\u65b0\u3002</p>\\n</li>\\n</ol>\\n","content":"<p>\u5728 x \u8f74\u4e0a\u6709\u4e00\u4e2a\u4e00\u7ef4\u7684\u82b1\u56ed\u3002\u82b1\u56ed\u957f\u5ea6\u4e3a&nbsp;<code>n</code>\uff0c\u4ece\u70b9&nbsp;<code>0</code>&nbsp;\u5f00\u59cb\uff0c\u5230\u70b9&nbsp;<code>n</code>&nbsp;\u7ed3\u675f\u3002</p>\\n\\n<p>\u82b1\u56ed\u91cc\u603b\u5171\u6709&nbsp;<code>n + 1</code> \u4e2a\u6c34\u9f99\u5934\uff0c\u5206\u522b\u4f4d\u4e8e&nbsp;<code>[0, 1, ..., n]</code> \u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570&nbsp;<code>n</code>&nbsp;\u548c\u4e00\u4e2a\u957f\u5ea6\u4e3a&nbsp;<code>n + 1</code> \u7684\u6574\u6570\u6570\u7ec4&nbsp;<code>ranges</code>&nbsp;\uff0c\u5176\u4e2d&nbsp;<code>ranges[i]</code> \uff08\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff09\u8868\u793a\uff1a\u5982\u679c\u6253\u5f00\u70b9&nbsp;<code>i</code>&nbsp;\u5904\u7684\u6c34\u9f99\u5934\uff0c\u53ef\u4ee5\u704c\u6e89\u7684\u533a\u57df\u4e3a&nbsp;<code>[i -&nbsp; ranges[i], i + ranges[i]]</code>&nbsp;\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u53ef\u4ee5\u704c\u6e89\u6574\u4e2a\u82b1\u56ed\u7684&nbsp;<strong>\u6700\u5c11\u6c34\u9f99\u5934\u6570\u76ee</strong>&nbsp;\u3002\u5982\u679c\u82b1\u56ed\u59cb\u7ec8\u5b58\u5728\u65e0\u6cd5\u704c\u6e89\u5230\u7684\u5730\u65b9\uff0c\u8bf7\u4f60\u8fd4\u56de&nbsp;<strong>-1</strong>&nbsp;\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/19/1685_example_1.png\\" style=\\"width: 530px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 5, ranges = [3,4,1,1,0,0]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u70b9 0 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [-3,3]\\n\u70b9 1 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [-3,5]\\n\u70b9 2 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [1,3]\\n\u70b9 3 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [2,4]\\n\u70b9 4 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [4,4]\\n\u70b9 5 \u5904\u7684\u6c34\u9f99\u5934\u53ef\u4ee5\u704c\u6e89\u533a\u95f4 [5,5]\\n\u53ea\u9700\u8981\u6253\u5f00\u70b9 1 \u5904\u7684\u6c34\u9f99\u5934\u5373\u53ef\u704c\u6e89\u6574\u4e2a\u82b1\u56ed [0,5] \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, ranges = [0,0,0,0]\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>\u5373\u4f7f\u6253\u5f00\u6240\u6709\u6c34\u9f99\u5934\uff0c\u4f60\u4e5f\u65e0\u6cd5\u704c\u6e89\u6574\u4e2a\u82b1\u56ed\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 7, ranges = [1,2,1,0,2,1,0,1]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 8, ranges = [4,0,0,0,0,0,0,0,4]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 8, ranges = [4,0,0,0,4,0,0,0,4]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 10^4</code></li>\\n\\t<li><code>ranges.length == n + 1</code></li>\\n\\t<li><code>0 &lt;= ranges[i] &lt;= 100</code></li>\\n</ul>\\n","title":"1326. \u704c\u6e89\u82b1\u56ed\u7684\u6700\u5c11\u6c34\u9f99\u5934\u6570\u76ee","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1326"}')}}]);